  { id: 'VG-102', title: 'BoConcept Coffee Table', premiumBrand: 'BoConcept', category: 'LIVING ROOM', subCategory: 'Tables', material: 'Engineered Wood', originalPrice: 45000, discount: 10, finalPrice: 40500, stockStatus: 'In Stock', stockQuantity: 25, imageUrl: 'https://images.unsplash.com/photo-1532372320572-cda25653a26d?w=400&q=80' },
  { id: 'VG-107', title: 'Herman Miller Aeron Chair', premiumBrand: 'Herman Miller', category: 'STUDY', subCategory: 'Office Chairs', material: 'Breathable Mesh', originalPrice: 115000, discount: 5, finalPrice: 109250, stockStatus: 'Out of Stock', stockQuantity: 0, imageUrl: 'https://images.unsplash.com/photo-1505843490538-5133c6c7d0e1?w=400&q=80' },
  { id: 'VG-110', title: 'FabIndia Bookshelf', premiumBrand: 'FabIndia', category: 'STUDY', subCategory: 'Storage', material: 'Mango Wood', originalPrice: 35000, discount: 20, finalPrice: 28000, stockStatus: 'In Stock', stockQuantity: 15, imageUrl: 'https://images.unsplash.com/photo-1594620302200-9a762244a156?w=400&q=80' },
  { id: 'VG-115', title: 'Pepperfry Sideboard', premiumBrand: 'Pepperfry', category: 'DINING', subCategory: 'Dining Storage', material: 'Sheesham Wood', originalPrice: 26000, discount: 15, finalPrice: 22100, stockStatus: 'Low Stock', stockQuantity: 2, imageUrl: 'https://images.unsplash.com/photo-1600607686527-6fb886090705?w=400&q=80' }
];

const sidebarCategories = {
  'LIVING ROOM': {
    'SOFAS': ['Fabric Sofas', 'Wooden Sofas', 'L-Shaped Sofas', 'Sofa Cum Beds', 'Recliners'],
    'SEATING': ['Lounge Chairs', 'Accent Chairs', 'Wing Chairs', 'Benches', 'Pouffes'],
    'TABLES': ['Coffee Tables', 'Side Tables', 'Console Tables', 'End Tables'],
    'STORAGE': ['TV Units', 'Bookshelves', 'Display Units', 'Shoe Racks']
  },
  'BEDROOM': {
    'BEDS': ['Solid Wood Beds', 'Upholstered Beds', 'Beds with Storage', 'King Size Beds', 'Queen Size Beds'],
    'STORAGE': ['Wardrobes', 'Chest of Drawers', 'Bedside Tables', 'Dressers'],
    'MATTRESSES': ['Memory Foam', 'Orthopedic', 'Dual Comfort', 'Coir Mattresses']
  },
  'DINING': {
    'DINING SETS': ['4 Seater Dining Sets', '6 Seater Dining Sets', '8 Seater Dining Sets', 'Extendable Dining'],
    'DINING STORAGE': ['Crockery Units', 'Kitchen Cabinets', 'Sideboards'],
    'DINING DECOR': ['Table Linens', 'Coasters', 'Dining Serveware']
  },
  'STUDY': {
    'STUDY TABLES': ['Solid Wood Tables', 'Computer Tables', 'Foldable Tables'],
    'OFFICE CHAIRS': ['Ergonomic Chairs', 'Executive Chairs', 'Study Chairs'],
    'OFFICE STORAGE': ['File Cabinets', 'Office Bookcases', 'Wall Shelves']
  }
};

const ProductsPage = () => {
  const [activeMainCategory, setActiveMainCategory] = useState(null); // Controls the accordion
  const [activeSubCategory, setActiveSubCategory] = useState('All Products'); // Controls filtering
  const [sortBy, setSortBy] = useState('Newest');

  // Filter products based on selection
  const filteredProducts = initialProducts.filter(product => {
    if (activeSubCategory === 'All Products') return true;
    return product.category === activeSubCategory || product.subCategory === activeSubCategory;
  });

  const handleCategoryClick = (categoryName) => {
    // Toggle Accordion open/close
    setActiveMainCategory(activeMainCategory === categoryName ? null : categoryName);
    // Set filter to this main category
    setActiveSubCategory(categoryName);
  };

  return (
    <div className="bg-gray-50 min-h-screen py-8">
      <div className="container mx-auto px-4">

        {/* Top Header */}
        <div className="mb-6 text-gray-500 text-sm">
          Showing 1 - {filteredProducts.length} of {initialProducts.length} products <span className="text-orange-500">(Demo Data)</span>
        </div>

        <div className="flex flex-col lg:flex-row gap-8">

          {/* LEFT SIDEBAR */}
          <div className="w-full lg:w-1/4 space-y-6">

            {/* Categories Box */}
            <div className="bg-white p-5 rounded-lg shadow-sm border border-gray-100">
              <h2 className="text-xl font-bold text-gray-900 mb-4">Categories</h2>

              <div className="space-y-2">
                {/* All Products Button */}
                <button
                  onClick={() => { setActiveMainCategory(null); setActiveSubCategory('All Products'); }}
                  className={`w-full text-left px-4 py-3 rounded-md font-medium transition-colors border ${activeSubCategory === 'All Products'
                      ? 'bg-orange-500 text-white border-orange-600 shadow-inner'
                      : 'bg-gray-50 text-gray-700 border-gray-100 hover:bg-gray-100'
                    }`}
                >
                  All Products
                </button>

                {/* Main Categories Accordion */}
                {Object.keys(sidebarCategories).map((mainCat) => (
                  <div key={mainCat} className="flex flex-col">
                    <button
                      onClick={() => handleCategoryClick(mainCat)}
                      className={`w-full flex items-center justify-between px-4 py-3 rounded-md font-medium transition-colors border ${activeMainCategory === mainCat
                          ? 'bg-orange-50 text-orange-600 border-orange-200'
                          : 'bg-gray-50 text-gray-700 border-gray-100 hover:bg-gray-100'
                        }`}
                    >
                      <span className="capitalize">{mainCat.toLowerCase()}</span>
                      {activeMainCategory === mainCat ? <ChevronUp size={18} /> : <ChevronDown size={18} />}
                    </button>

                    {/* Subcategories Dropdown (Smooth reveal) */}
                    <div className={`overflow-hidden transition-all duration-300 ease-in-out ${activeMainCategory === mainCat ? 'max-h-[1000px] mt-2 opacity-100' : 'max-h-0 opacity-0'}`}>
                      <div className="pl-4 pr-2 space-y-4 py-2 border-l-2 border-orange-200 ml-4">
                        {Object.entries(sidebarCategories[mainCat]).map(([groupName, items]) => (
                          <div key={groupName}>
                            <h4 className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">{groupName}</h4>
                            <ul className="space-y-1.5 pl-2">
                              {items.map(item => (
                                <li key={item}>
                                  <button
                                    onClick={() => setActiveSubCategory(item)}
                                    className={`text-sm text-left w-full hover:text-orange-500 transition-colors ${activeSubCategory === item ? 'text-orange-500 font-semibold' : 'text-gray-600'}`}
                                  >
                                    {item}
                                  </button>
                                </li>
                              ))}
                            </ul>
                          </div>
                        ))}
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* Sort By Box */}
            <div className="bg-white p-5 rounded-lg shadow-sm border border-gray-100">
              <h2 className="text-xl font-bold text-gray-900 mb-4">Sort By</h2>
              <select
                value={sortBy}
                onChange={(e) => setSortBy(e.target.value)}
                className="w-full bg-white border border-gray-200 text-gray-700 py-2.5 px-4 rounded-md outline-none focus:ring-2 focus:ring-orange-500 focus:border-transparent cursor-pointer"
              >
                <option value="Newest">Newest</option>
                <option value="Price: Low to High">Price: Low to High</option>
                <option value="Price: High to Low">Price: High to Low</option>
                <option value="Discount">Highest Discount</option>
              </select>
            </div>

          </div>

          {/* RIGHT PRODUCT GRID */}
          <div className="w-full lg:w-3/4">
            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">

              {filteredProducts.map((product) => (
                <div key={product.id} className="bg-white rounded-xl overflow-hidden shadow-sm hover:shadow-lg transition-shadow duration-300 border border-gray-100 flex flex-col">

                  {/* Image Container */}
                  <div className="relative h-56 bg-gray-100 overflow-hidden group">
                    {/* Discount Tag */}
                    {product.discount > 0 && (
                      <div className="absolute top-3 left-3 bg-[#e53935] text-white text-xs font-bold px-2 py-1 rounded shadow-sm z-10">
                        {product.discount}% OFF
                      </div>
                    )}

                    {/* Wishlist Button */}
                    <button className="absolute top-3 right-3 bg-white p-1.5 rounded-full text-gray-400 hover:text-red-500 shadow-sm z-10 transition-colors">
                      <Heart size={18} />
                    </button>

                    <img
                      src={product.imageUrl}
                      alt={product.title}
                      className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"
                    />
                  </div>

                  {/* Product Details */}
                  <div className="p-5 flex flex-col flex-grow">
                    <h3 className="text-lg font-bold text-gray-900 mb-1 leading-tight line-clamp-1">
                      {product.title}
                    </h3>
                    <p className="text-sm text-gray-500 mb-4">
                      {product.material}
                    </p>

                    {/* Pricing */}
                    <div className="flex items-center gap-2 mb-3">
                      <span className="text-xl font-bold text-gray-900">
                        ₹{product.finalPrice.toLocaleString('en-IN')}
                      </span>
                      {product.discount > 0 && (
                        <span className="text-sm text-gray-400 line-through">
                          ₹{product.originalPrice.toLocaleString('en-IN')}
                        </span>
                      )}
                    </div>

                    {/* Stock Status Indicator */}
                    <div className="flex items-center gap-1.5 mb-5 text-sm font-medium">
                      {product.stockQuantity > 5 ? (
                        <><CheckCircle2 size={16} className="text-green-600" /><span className="text-green-600">In Stock</span></>
                      ) : product.stockQuantity > 0 ? (
                        <><Clock size={16} className="text-orange-500" /><span className="text-orange-500">Only {product.stockQuantity} left</span></>
                      ) : (
                        <><XCircle size={16} className="text-red-500" /><span className="text-red-500">Out of Stock</span></>
                      )}
                    </div>

                    {/* Add to Cart Button */}
                    <button
                      disabled={product.stockQuantity === 0}
                      className={`w-full py-2.5 rounded-md font-bold flex items-center justify-center gap-2 transition-colors mt-auto ${product.stockQuantity === 0
                          ? 'bg-gray-200 text-gray-400 cursor-not-allowed'
                          : 'bg-[#f97316] hover:bg-[#ea580c] text-white shadow-sm'
                        }`}
                    >
                      <ShoppingCart size={18} />
                      ADD TO CART
                    </button>
                  </div>

                </div>
              ))}

              {/* Empty State if category has no products */}
              {filteredProducts.length === 0 && (
                <div className="col-span-full py-12 text-center bg-white rounded-lg border border-gray-100">
                  <p className="text-gray-500 font-medium">No products found in this category.</p>
                  <button
                    onClick={() => { setActiveMainCategory(null); setActiveSubCategory('All Products'); }}
                    className="mt-4 text-orange-500 font-bold hover:underline"
                  >
                    Clear Filters
                  </button>
                </div>
              )}

            </div>
          </div>

        </div>
      </div>
    </div>
  );
};

export default ProductsPage;
